class Solution {
    public int wordCount(String[] startWords, String[] targetWords) {
        int count = 0;
        for (int i = 0; i < targetWords.length; i++) {
            for (int j = 0; j < startWords.length; j++) {
                if (isValidWord(targetWords[i], startWords[j])) {
                    count++;
                }
            }
        }
        return count;
    }

